#include <bits/stdc++.h>
using namespace std;

const int N=2e5+5;

int n,nxt[15],ans;
string p[205],s;
bool b[N][15],f[N];

int main(){
    ios::sync_with_stdio(false);
    cin.tie(0),cout.tie(0);
    while(cin>>p[++n])
        if(p[n]==".")
            break;
    n--;
    string t;
    while(cin>>t)
    	s+=t;
    for(int i=1;i<=n;i++){
        nxt[0]=0;
        for(int j=1,k=0;j<p[i].size();j++){
            while(p[i][j]!=p[i][k] && k)
                k=nxt[k-1];
            if(p[i][j]==p[i][k])
                k++;
            nxt[j]=k;
        }
        for(int j=0,k=0;j<s.size();j++){
            while(s[j]!=p[i][k] && k)
                k=nxt[k-1];
            if(s[j]==p[i][k])
                k++;
            if(k==p[i].size())
                b[j+1][k]=1,k=nxt[k-1];
        }
    }
    f[0]=1;
    for(int i=1;i<=s.size();i++){
        for(int j=1;j<=min(i,10);j++)
            if(b[i][j])
                f[i]|=f[i-j];
        if(f[i])
            ans=i;
    }
    cout<<ans;
    return 0;
}
